#include <vector>
#include <map>
#include <priority_queue>
#include <algorithm>

using namespace std;

class DSU {
    vector<int> parent;
    vector<int> rank;
public:
    DSU(int n) {
        parent.resize(n+1, 0);
        rank.resize(n+1, 1);
        for (int i=1; i<=n; ++i) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    void unite(int x, int y) {
        int x_root = find(x);
        int y_root = find(y);
        if (x_root == y_root) return;
        if (rank[x_root] < rank[y_root]) {
            parent[x_root] = y_root;
        } else {
            parent[y_root] = x_root;
            if (rank[x_root] == rank[y_root]) rank[x_root]++;
        }
    }
};

vector<int64_t> solve(int64_t c, vector<vector<int64_t>> connections, vector<vector<int64_t>> queries) {
    DSU dsu(c);
    for (auto& conn : connections) {
        int u = conn[0];
        int v = conn[1];
        dsu.unite(u, v);
    }

    map<int, priority_queue<int, vector<int>, greater<int>>> component_heaps;
    for (int i = 1; i <= c; ++i) {
        int root = dsu.find(i);
        component_heaps[root].push(i);
    }

    vector<int64_t> result;
    vector<bool> online(c+1, true);

    for (auto& query : queries) {
        int type = query[0];
        int x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                int root = dsu.find(x);
                while (!component_heaps[root].empty()) {
                    int top = component_heaps[root].top();
                    if (online[top]) {
                        result.push_back(top);
                        break;
                    } else {
                        component_heaps[root].pop();
                    }
                }
                if (component_heaps[root].empty()) {
                    result.push_back(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}
